function solve(code: string[], businessLine: string[], isActive: boolean[]): string[] {
    // Define the order of business lines
    const businessOrder: string[] = ["electronics", "grocery", "pharmacy", "restaurant"];

    // Filter valid coupons
    const validCoupons: { code: string; businessLine: string; isActive: boolean }[] = [];

    for (let i = 0; i < code.length; i++) {
        // Check if code is valid
        const codeValid = code[i] && /^[a-zA-Z0-9_]+$/.test(code[i]);
        // Check if business line is valid
        const businessValid = businessOrder.includes(businessLine[i]);
