            boolean businessValid = businessOrder.contains(businessLine[i]);
            // Check if active
            boolean active = isActive[i];

            if (codeValid && businessValid && active) {
                Map<String, Object> coupon = new HashMap<>();
                coupon.put("code", code[i]);
                coupon.put("businessLine", businessLine[i]);
                coupon.put("isActive", active);
                validCoupons.add(coupon);
            }
        }

        // Sort by business line order and then by code lexicographically
        validCoupons.sort((a, b) -> {
            int businessIndexA = businessOrder.indexOf((String) a.get("businessLine"));
            int businessIndexB = businessOrder.indexOf((String) b.get("businessLine"));

            if (businessIndexA != businessIndexB) {
                return Integer.compare(businessIndexA, businessIndexB);
            }
            return ((String) a.get("code")).compareTo((String) b.get("code"));
        });

        // Extract the codes in order
        String[] result = new String[validCoupons.size()];
        for (int i = 0; i < result.length; i++) {
            result[i] = (String) validCoupons.get(i).get("code");
        }

        return result;
    }
}
